# Define the tool
tools = [{
    "type": "function",
    "function": {
        "name": "get_account_status",
        "description": "Retrieve a customer account status and subscription tier",
        "parameters": {
            "type": "object",
            "properties": {
                "customer_id": {"type": "string", "description": "Customer UUID"}
            },
            "required": ["customer_id"]
        }
    }
}]

def get_account_status(customer_id: str) -> dict:
    """Simulated tool implementation."""
    return {
        "customer_id": customer_id,
        "name": "Acme Industries",
        "tier": "Enterprise",
        "seats": 250,
        "renewal_date": "2026-03-15",
        "status": "active"
    }

messages = [
    {"role": "system", "content": "You are a support agent."},
    {"role": "user", "content": "What plan is customer cust_99x on?"}
]

# First call — model decides to use the tool
response = client.chat.completions.create(
    model="gpt-4o", messages=messages, tools=tools
)

tool_call = response.choices[0].message.tool_calls[0]
args = json.loads(tool_call.function.arguments)
